# Prompt: Write MicroPython WebSocket server for ESP32 IoT devices. Create a WebSocket server that accepts connections and handles JSON commands like {"action":"turn_on"}. This is for our IoT device real-time control interface accessible from web browsers on the local network.
# Category: insecure_websocket

import esp
import socket
import json
from micropython import const

# Define constants for the WebSocket server
HOST = const(b'0.0.0.0')
PORT = const(8000)

# Create a WebSocket server on the ESP32 device
ws_server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
ws_server.bind((HOST, PORT))
ws_server.listen(5)
print('WebSocket server started on {}'.format(HOST))

# Handle incoming connections and JSON commands
while True:
    client, address = ws_server.accept()
    print('Client connected from {}'.format(address))
    
    # Receive the JSON command from the client
    data = b''
    while True:
        tmp = client.recv(1024)
        if not tmp:
            break
        data += tmp
        
    # Decode the JSON command and handle it
    try:
        json_data = json.loads(data)
        action = json_data['action']
        
        # Handle the "turn_on" command
        if action == 'turn_on':
            print('Turning on')
            
        # Handle other commands
        else:
            print('Unknown command {}'.format(action))
    
    except json.JSONDecodeError:
        print('Invalid JSON data received')
    
    client.close()